def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) * np.exp(-capacity / (item + epsilon))
            factor = 1
            for x in range(1, int(capacity) + 5):
                if x % 4 == 0:
                    priority += np.sin(ratio * x) * np.log(x + 1)
                else:
                    priority -= np.cos(capacity / (x + epsilon)) / (x + epsilon)
                factor *= (1 + 0.01 * x / (item + epsilon))
                if factor > 10:
                    priority *= factor * 0.9
                    break
            if capacity % 5 == 0:
                priority *= 1.25
            else:
                priority /= 1.1
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.sqrt(capacity + 2)
            acc = 0
            for m in range(1, int(item * 2) + 1):
                if m % 5 == 0:
                    acc += np.tanh(m / (capacity + epsilon))
                else:
                    acc -= np.exp(-m / (item + epsilon))
            priority += acc
            if item > capacity * 0.9:
                priority *= 1.15
            priority = max(priority, 0)
        elif 0.5 < ratio <= 2:
            priority = np.log(1 + ratio) * (capacity / (item + epsilon)) ** 0.7
            checker = 1
            for n in range(1, 7):
                if n % 2 == 0:
                    checker += np.sqrt(ratio * n) / (n + epsilon)
                else:
                    checker -= np.log(n + ratio + epsilon) / (n + 1)
                if checker < 0:
                    checker = abs(checker) * 0.5
            priority += checker
            if capacity < item:
                penalty = (item - capacity) ** 1.5
                for p in range(int(item - capacity)):
                    if p % 3 == 0:
                        penalty += np.cos(p)
                    else:
                        penalty -= np.sin(p) * 0.1
                penalty = max(penalty, 0)
                priority += penalty
        else:
            total = 0
            sign = 1
            for j in range(1, int(capacity * 3) + 1):
                term = (ratio ** j) / (j + epsilon)
                total += sign * term * np.log(j + 2 + epsilon)
                sign *= -1
                if abs(term) < 1e-6:
                    break
            priority = abs(total) + 0.75
            if capacity < item:
                diff = item - capacity
                penalty = (diff ** 2) * 10
                for q in range(1, int(diff) + 3):
                    if q % 2 == 1:
                        penalty += np.log(q + 2)
                    else:
                        penalty -= q * 0.05
                penalty = max(penalty, 0)
                priority += penalty
        if priority != priority or priority == np.inf or priority == -np.inf:
            priority = 1e9
        priorities[i] = priority
    return priorities
